// --- 1. OBTENCIÓN DE DATOS ---
const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });
const textoCliente = $('Email Trigger (IMAP)').item.json.textPlain || "";
const nombreCliente = $('Obtiene cliente').item.json.nombre || "Cliente";
const rawIA = $('LLM crea respuesta SLA').item.json.text || "";
const idGenerado = "TK-" + Math.floor(Date.now() / 1000);

// --- 2. PROCESAMIENTO ---
let respuestaParaCliente = rawIA;
let dbModulo = "General"; 
let dbPrioridad = "Media";

try {
  const jsonLimpio = rawIA.replace(/```json/g, '').replace(/```/g, '').trim();
  if (jsonLimpio.startsWith('{')) {
    const objetoIA = JSON.parse(jsonLimpio);
    dbModulo = objetoIA.modulo || "General";
    dbPrioridad = objetoIA.prioridad || "Media";
    if (objetoIA.respuesta_sugerida) {
       // Limpieza para evitar doble saludo
       respuestaParaCliente = objetoIA.respuesta_sugerida.replace(/^Hola\s+[^,]+,\s*/i, '').trim();
    }
  }
} catch (e) {}

function hacerHtmlBonito(contenido, nombre) {
  const emailUsuario = $('Email Trigger (IMAP)').item.json.from.match(/<([^>]+)>/)?.[1] || $('Email Trigger (IMAP)').item.json.from;
  let cuerpo = contenido.replace(/\n/g, '<br>');

  return `
    <div style="font-family: 'Segoe UI', Helvetica, Arial, sans-serif; color: #333; line-height: 1.6; max-width: 600px; margin: 0 auto; border: 1px solid #eee; padding: 20px; border-radius: 12px;">
      <h2 style="color: #FF4B4B; margin-top: 0;">Soporte Nexus ERP</h2>
      <p>Hola <b>${nombre}</b>,</p>
      <p>Hemos registrado tu solicitud correctamente. Aquí tienes la respuesta de nuestro equipo:</p>

      <div style="background-color: #f9f9f9; padding: 15px; border-left: 4px solid #FF4B4B; margin-bottom: 25px;">
        ${cuerpo}
      </div>

      <div style="background-color: #ffffff; border: 2px solid #f0f2f6; padding: 20px; border-radius: 10px; text-align: center;">
        <a href="https://portclientes.streamlit.app/" 
           style="background-color: #FF4B4B; color: white; padding: 14px 28px; text-decoration: none; border-radius: 8px; font-weight: bold; display: inline-block; font-size: 16px;">
           Acceder al Portal de Clientes
        </a>

        <div style="margin-top: 20px; padding-top: 15px; border-top: 1px solid #eee; text-align: left;">
          <p style="margin: 0; font-size: 14px; color: #555;"><b>Instrucciones de acceso (Versión DEMO):</b></p>
          <ul style="margin: 5px 0; padding-left: 20px; font-size: 13px; color: #666;">
            <li><b>Usuario:</b> ${emailUsuario}</li>
            <li><b>Contraseña:</b> 1234</li>
          </ul>
          <p style="margin: 10px 0 0 0; font-size: 12px; color: #888; font-style: italic;">
            * Por seguridad, podrás actualizar tu contraseña una vez que hayas ingresado al sistema.
          </p>
        </div>
      </div>

      <p style="font-size: 13px; color: #999; margin-top: 30px; text-align: center;">
        Ticket ID: <b>${idGenerado}</b><br>
        &copy; 2026 Nexus ERP Portfolio Project
      </p>
    </div>
  `;
}

// --- 3. CONSTRUCCIÓN DEL HISTORIAL ---
const clienteSafe = textoCliente.replace(/'/g, "''");
const iaSafe = respuestaParaCliente.replace(/'/g, "''");
const bloqueHistorial = `[CLIENTE - ${fecha}]:\n${clienteSafe}\n\n[SOPORTE IA]:\n${iaSafe}\n`;

return {
  id_generado: idGenerado,
  actualizacion_historial: bloqueHistorial,
  email_html_bonito: hacerHtmlBonito(respuestaParaCliente, nombreCliente),
  modulo_ticket: dbModulo,
  prioridad_ticket: dbPrioridad
};

// --- FUNCIONES DE SEGURIDAD ---
function buscarDato(nombreNodo, campo, valorPorDefecto) {
  try {
    const nodo = $(nombreNodo);
    if (nodo && nodo.item && nodo.item.json) return nodo.item.json[campo] || valorPorDefecto;
    return valorPorDefecto;
  } catch (error) {
    return valorPorDefecto;
  }
}

// --- 1. OBTENCIÓN DE DATOS BÁSICOS (IGUAL AL ORIGINAL) ---
const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });
const idTicket = buscarDato('Extraer ID', 'ticket_id', "SIN_ID");
const nombreCliente = buscarDato('Obtiene cliente', 'nombre', "Cliente");
const textoCliente = buscarDato('Email Trigger (IMAP)', 'textPlain', "Sin mensaje legible.");

// --- 2. PROCESAMIENTO DE DATOS DE LA IA ---
// Obtenemos el objeto que limpiamos en "Tranformar a JSON"
const datosIA = $node["Tranformar a JSON"].json.datos_limpios; 
const rawRespuestaIA = datosIA.email_respuesta || "Estamos procesando su solicitud.";
const dbModulo = datosIA.modulo || "General";
const dbPrioridad = datosIA.prioridad || "Media";

// Manejo de datos faltantes (por si la IA detectó que falta info, igual que tu original)
let dbDatosFaltantes = "";
let cuerpoEmailFinal = rawRespuestaIA;

// Si tu JSON de IA llega a incluir una lista de datos faltantes, los formateamos igual
if (datosIA.datos_faltantes && Array.isArray(datosIA.datos_faltantes)) {
    dbDatosFaltantes = datosIA.datos_faltantes.map((pregunta, index) => `${index + 1}. ${pregunta}`).join('\n');
    cuerpoEmailFinal = `
        Hemos analizado su reporte.<br>
        Para poder resolverlo, necesitamos que nos brinde la siguiente información:
        <ul>
            <li>${datosIA.datos_faltantes.join('</li><li>')}</li>
        </ul>
    `;
}

// --- 3. FUNCIÓN HTML BONITO (IDÉNTICA AL ORIGINAL) ---
function hacerHtmlBonito(contenido, nombre) {
  let cuerpo = contenido;
  if (!cuerpo.includes('<ul')) {
      cuerpo = cuerpo.replace(/\n/g, '<br>');
  }

  return `
    <div style="font-family: Arial, sans-serif; color: #333333; line-height: 1.6; font-size: 14px;">
      Hola <b>${nombre}</b>,<br><br>
      Gracias por contactar a Soporte.<br><br>
      ${cuerpo}
      <br><br>
      <hr style="border: 0; border-top: 1px solid #eeeeee;">
      <small style="color: #888888;">Ticket ID: ${idTicket}</small>
    </div>
  `;
}

// --- 4. PREPARACIÓN PARA BASE DE DATOS Y DASHBOARD ---
const clienteSafe = (textoCliente || "").replace(/'/g, "''");
const iaSafe = rawRespuestaIA.replace(/<[^>]*>?/gm, ' ').replace(/'/g, "''");

const bloqueHistorial = `
[CLIENTE - ${fecha}]:
${clienteSafe}

----------------------------------------

[SOPORTE IA - ${fecha}]:
${iaSafe}

----------------------------------------
`;

return {
  id_ticket_limpio: idTicket.toString().trim(), 
  actualizacion_historial: bloqueHistorial,
  email_html_bonito: hacerHtmlBonito(cuerpoEmailFinal, nombreCliente),
  modulo_ticket: dbModulo,
  prioridad_ticket: dbPrioridad,
  datos_faltantes_lista: dbDatosFaltantes
};

// --- FUNCIONES DE SEGURIDAD ---
function buscarDato(nombreNodo, campo, valorPorDefecto) {
  try {
    if ($(nombreNodo) && $(nombreNodo).item && $(nombreNodo).item.json) {
      const valor = $(nombreNodo).item.json[campo];
      return (valor !== undefined && valor !== null) ? valor : valorPorDefecto;
    } 
    else if ($(nombreNodo) && $(nombreNodo).first && $(nombreNodo).first().json) {
       const valor = $(nombreNodo).first().json[campo];
       return (valor !== undefined && valor !== null) ? valor : valorPorDefecto;
    }
    return valorPorDefecto;
  } catch (error) {
    return valorPorDefecto;
  }
}

// --- 1. OBTENCIÓN DE DATOS ---
const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

const idTicket = buscarDato('Extraer ID', 'ticket_id', "SIN_ID");
const nombreCliente = buscarDato('Get many rows', 'nombre', "Cliente");
const textoCliente = buscarDato('Email Trigger (IMAP)', 'textPlain', "Sin mensaje legible.");
const rawIA = buscarDato('Basic LLM Chain1', 'text', "");

// --- 2. PROCESAMIENTO INTELIGENTE ---
let respuestaParaCliente = rawIA;
let dbModulo = "General"; 
let dbPrioridad = "Media";
let dbDatosFaltantes = "";

try {
  const jsonLimpio = rawIA.replace(/```json/g, '').replace(/```/g, '').trim();

  if (jsonLimpio.startsWith('{')) {
    const objetoIA = JSON.parse(jsonLimpio);
    dbModulo = objetoIA.modulo || "General";
    dbPrioridad = objetoIA.prioridad || "Media";

    if (objetoIA.datos_faltantes && Array.isArray(objetoIA.datos_faltantes)) {
      dbDatosFaltantes = objetoIA.datos_faltantes.map((pregunta, index) => `${index + 1}. ${pregunta}`).join('\n');
    }

    if (objetoIA.datos_faltantes && Array.isArray(objetoIA.datos_faltantes) && objetoIA.datos_faltantes.length > 0) {
      respuestaParaCliente = `
        Hemos analizado su reporte sobre <b>"${objetoIA.resumen || 'el incidente'}"</b>.<br>
        Para poder resolverlo, necesitamos que nos brinde la siguiente información:
        <ul>
          <li>${objetoIA.datos_faltantes.join('</li><li>')}</li>
        </ul>
      `;
    } else if (objetoIA.respuesta) {
      respuestaParaCliente = objetoIA.respuesta;
    } else {
       respuestaParaCliente = jsonLimpio;
    }
  }
} catch (e) {
  respuestaParaCliente = rawIA.replace(/```json/g, '').replace(/```/g, '');
  dbDatosFaltantes = rawIA;
}

function hacerHtmlBonito(contenido, nombre) {
  let cuerpo = contenido;
  if (!cuerpo.includes('<ul')) {
      cuerpo = cuerpo.replace(/\n/g, '<br>');
  }

  return `
    <div style="font-family: Arial, sans-serif; color: #333333; line-height: 1.6; font-size: 14px;">
      Hola <b>${nombre}</b>,<br><br>
      Gracias por contactar a Soporte.<br><br>
      ${cuerpo}
      <br><br>
      <hr style="border: 0; border-top: 1px solid #eeeeee;">
      <small style="color: #888888;">Ticket ID: ${idTicket}</small>
    </div>
  `;
}

// --- 4. PREPARACIÓN BASE DE DATOS (AQUÍ ESTÁ LA MAGIA) ---
const clienteSafe = (textoCliente || "").replace(/'/g, "''");
const iaSafe = respuestaParaCliente.toString().replace(/<[^>]*>?/gm, ' ').replace(/'/g, "''");

// ESTE ES EL FORMATO QUE VERÁS EN EL DASHBOARD
const bloqueHistorial = `
[CLIENTE - ${fecha}]:
${clienteSafe}

----------------------------------------

[SOPORTE IA - ${fecha}]:
${iaSafe}

----------------------------------------
`;

return {
  id_ticket_limpio: idTicket.toString().trim(), 
  actualizacion_historial: bloqueHistorial,
  email_html_bonito: hacerHtmlBonito(respuestaParaCliente, nombreCliente),
  modulo_ticket: dbModulo,
  prioridad_ticket: dbPrioridad,
  datos_faltantes_lista: dbDatosFaltantes
};

const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

// 1. OBTENCIÓN DEL DATO DE ENTRADA (Corregido)
// Usamos $json para leer directamente lo que entra al nodo actual
const htmlAnterior = $('Actualiza Historial y crea email html IA').first().json.email_html_bonito|| ""; 

// 2. MENSAJE DEL SISTEMA
const mensajeSistema = "Su respuesta ha sido recibida correctamente. El estado de su ticket ha cambiado a 'En Revisión'.";

// 3. CONCATENACIÓN DEL EMAIL HTML
// Unimos el aviso con el diseño previo
const emailHtml = `
  <div style="font-family: Arial, sans-serif; color: #333;">
    <p><b>${mensajeSistema}</b></p>
    <hr style="border: 0; border-top: 1px solid #eee; margin: 20px 0;">
    ${htmlAnterior}
    <br><br>
    Saludos,<br><b>Equipo de Soporte</b>
  </div>
`;

// 4. LOG PARA EL HISTORIAL (Solo texto plano)
const logSistema = `
[SISTEMA - ${fecha}]:
${mensajeSistema}

----------------------------------------
`;

return {
  nuevo_estado: "En Revisión",
  actualizacion_sistema: logSistema,
  email_respuesta: emailHtml
};
